import{_ as t,o as s,c as e,ag as n}from"./chunks/framework.BVdG3tbf.js";const b=JSON.parse('{"title":"DEFORM 安装与配置","description":"","frontmatter":{},"headers":[],"relativePath":"deform/basics/installation.md","filePath":"deform/basics/installation.md","lastUpdated":null}'),l={name:"deform/basics/installation.md"};function d(i,a,o,r,p,h){return s(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="deform-安装与配置" tabindex="-1">DEFORM 安装与配置 <a class="header-anchor" href="#deform-安装与配置" aria-label="Permalink to &quot;DEFORM 安装与配置&quot;">​</a></h1><p>本教程介绍 DEFORM 软件的安装和基本配置方法。</p><h2 id="📋-系统要求" tabindex="-1">📋 系统要求 <a class="header-anchor" href="#📋-系统要求" aria-label="Permalink to &quot;📋 系统要求&quot;">​</a></h2><h3 id="硬件要求" tabindex="-1">硬件要求 <a class="header-anchor" href="#硬件要求" aria-label="Permalink to &quot;硬件要求&quot;">​</a></h3><table tabindex="0"><thead><tr><th>配置</th><th>最低要求</th><th>推荐配置</th></tr></thead><tbody><tr><td><strong>操作系统</strong></td><td>Windows 10 (64位)</td><td>Windows 10/11 (64位)</td></tr><tr><td><strong>处理器</strong></td><td>Intel/AMD 多核</td><td>Intel i7/i9 或 AMD Ryzen 7/9</td></tr><tr><td><strong>内存</strong></td><td>8 GB</td><td>32 GB 或更高</td></tr><tr><td><strong>硬盘</strong></td><td>20 GB</td><td>SSD 100 GB+</td></tr><tr><td><strong>显卡</strong></td><td>支持 OpenGL</td><td>独立显卡（推荐 NVIDIA）</td></tr></tbody></table><h3 id="软件要求" tabindex="-1">软件要求 <a class="header-anchor" href="#软件要求" aria-label="Permalink to &quot;软件要求&quot;">​</a></h3><ul><li>Windows 10/11 (64位)</li><li>Microsoft Visual C++ Redistributable</li><li>.NET Framework 4.7 或更高</li></ul><h2 id="🔧-安装步骤" tabindex="-1">🔧 安装步骤 <a class="header-anchor" href="#🔧-安装步骤" aria-label="Permalink to &quot;🔧 安装步骤&quot;">​</a></h2><h3 id="步骤-1-获取安装包" tabindex="-1">步骤 1：获取安装包 <a class="header-anchor" href="#步骤-1-获取安装包" aria-label="Permalink to &quot;步骤 1：获取安装包&quot;">​</a></h3><ol><li>从 SFTC 获取 DEFORM 安装包</li><li>通常为 <code>DEFORM_v14.x.exe</code> 或类似文件名</li></ol><h3 id="步骤-2-运行安装程序" tabindex="-1">步骤 2：运行安装程序 <a class="header-anchor" href="#步骤-2-运行安装程序" aria-label="Permalink to &quot;步骤 2：运行安装程序&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>双击 DEFORM_v14.x.exe</span></span>
<span class="line"><span>→ 选择安装语言</span></span>
<span class="line"><span>→ 接受许可协议</span></span>
<span class="line"><span>→ 选择安装目录（建议：C:\\DEFORM）</span></span>
<span class="line"><span>→ 选择组件（推荐全部安装）</span></span>
<span class="line"><span>→ 等待安装完成</span></span></code></pre></div><h3 id="步骤-3-配置许可证" tabindex="-1">步骤 3：配置许可证 <a class="header-anchor" href="#步骤-3-配置许可证" aria-label="Permalink to &quot;步骤 3：配置许可证&quot;">​</a></h3><p><strong>单机许可证：</strong></p><ol><li>将许可证文件复制到安装目录</li><li>或设置环境变量 <code>DEFORM_LICENSE_FILE</code></li></ol><p><strong>网络许可证：</strong></p><ol><li>设置许可证服务器地址</li><li>环境变量：<code>DEFORM_LICENSE_FILE=port@server</code></li></ol><h3 id="步骤-4-验证安装" tabindex="-1">步骤 4：验证安装 <a class="header-anchor" href="#步骤-4-验证安装" aria-label="Permalink to &quot;步骤 4：验证安装&quot;">​</a></h3><ol><li>启动 DEFORM</li><li>检查是否能正常打开</li><li>运行示例文件验证</li></ol><h2 id="⚙️-基本配置" tabindex="-1">⚙️ 基本配置 <a class="header-anchor" href="#⚙️-基本配置" aria-label="Permalink to &quot;⚙️ 基本配置&quot;">​</a></h2><h3 id="工作目录设置" tabindex="-1">工作目录设置 <a class="header-anchor" href="#工作目录设置" aria-label="Permalink to &quot;工作目录设置&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tools → Options → General</span></span>
<span class="line"><span>→ Working Directory: D:\\DEFORM_Projects</span></span>
<span class="line"><span>→ Temporary Directory: D:\\DEFORM_Temp</span></span></code></pre></div><h3 id="显示设置" tabindex="-1">显示设置 <a class="header-anchor" href="#显示设置" aria-label="Permalink to &quot;显示设置&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tools → Options → Display</span></span>
<span class="line"><span>→ Background Color: White 或 Gray</span></span>
<span class="line"><span>→ Anti-aliasing: 4x 或更高</span></span>
<span class="line"><span>→ Font Size: 根据屏幕调整</span></span></code></pre></div><h3 id="计算设置" tabindex="-1">计算设置 <a class="header-anchor" href="#计算设置" aria-label="Permalink to &quot;计算设置&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tools → Options → Solver</span></span>
<span class="line"><span>→ Default Solver: Direct 或 Iterative</span></span>
<span class="line"><span>→ Number of CPU Cores: 根据系统设置</span></span>
<span class="line"><span>→ Memory Limit: 根据系统内存设置</span></span></code></pre></div><h2 id="📁-项目结构" tabindex="-1">📁 项目结构 <a class="header-anchor" href="#📁-项目结构" aria-label="Permalink to &quot;📁 项目结构&quot;">​</a></h2><h3 id="典型项目目录" tabindex="-1">典型项目目录 <a class="header-anchor" href="#典型项目目录" aria-label="Permalink to &quot;典型项目目录&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DEFORM_Project/</span></span>
<span class="line"><span>├── *.DB                    # DEFORM 数据库文件</span></span>
<span class="line"><span>├── *.KEY                   # 关键字文件</span></span>
<span class="line"><span>├── *.msg                   # 消息文件</span></span>
<span class="line"><span>├── *.plt                   # 后处理文件</span></span>
<span class="line"><span>├── STL/                    # STL 几何文件</span></span>
<span class="line"><span>│   ├── billet.stl</span></span>
<span class="line"><span>│   └── die.stl</span></span>
<span class="line"><span>├── Material/               # 材料数据</span></span>
<span class="line"><span>│   └── AISI-1045.def</span></span>
<span class="line"><span>└── Results/                # 计算结果</span></span>
<span class="line"><span>    ├── *.out</span></span>
<span class="line"><span>    └── *.log</span></span></code></pre></div><h3 id="文件类型说明" tabindex="-1">文件类型说明 <a class="header-anchor" href="#文件类型说明" aria-label="Permalink to &quot;文件类型说明&quot;">​</a></h3><table tabindex="0"><thead><tr><th>扩展名</th><th>文件类型</th><th>说明</th></tr></thead><tbody><tr><td><code>.DB</code></td><td>数据库文件</td><td>包含所有仿真设置</td></tr><tr><td><code>.KEY</code></td><td>关键字文件</td><td>前处理器输入</td></tr><tr><td><code>.msg</code></td><td>消息文件</td><td>计算过程信息</td></tr><tr><td><code>.plt</code></td><td>后处理文件</td><td>结果数据</td></tr><tr><td><code>.stl</code></td><td>几何文件</td><td>CAD 模型</td></tr></tbody></table><h2 id="🔍-常见问题" tabindex="-1">🔍 常见问题 <a class="header-anchor" href="#🔍-常见问题" aria-label="Permalink to &quot;🔍 常见问题&quot;">​</a></h2><h3 id="安装问题" tabindex="-1">安装问题 <a class="header-anchor" href="#安装问题" aria-label="Permalink to &quot;安装问题&quot;">​</a></h3><table tabindex="0"><thead><tr><th>问题</th><th>原因</th><th>解决方案</th></tr></thead><tbody><tr><td>安装失败</td><td>权限不足</td><td>以管理员身份运行</td></tr><tr><td>找不到许可证</td><td>许可证配置错误</td><td>检查许可证文件路径</td></tr><tr><td>启动崩溃</td><td>显卡驱动问题</td><td>更新显卡驱动</td></tr></tbody></table><h3 id="运行问题" tabindex="-1">运行问题 <a class="header-anchor" href="#运行问题" aria-label="Permalink to &quot;运行问题&quot;">​</a></h3><table tabindex="0"><thead><tr><th>问题</th><th>原因</th><th>解决方案</th></tr></thead><tbody><tr><td>计算很慢</td><td>CPU 核心设置不当</td><td>调整并行计算设置</td></tr><tr><td>内存不足</td><td>模型太大</td><td>增加内存或简化模型</td></tr><tr><td>显示异常</td><td>OpenGL 问题</td><td>更新显卡驱动</td></tr></tbody></table><h2 id="📖-下一步" tabindex="-1">📖 下一步 <a class="header-anchor" href="#📖-下一步" aria-label="Permalink to &quot;📖 下一步&quot;">​</a></h2><p>安装完成后，建议继续学习：</p><ul><li><a href="/simu-learn/deform/basics/interface.html">界面介绍</a></li><li><a href="/simu-learn/deform/basics/operations.html">基本操作</a></li></ul><hr><div class="tip custom-block"><p class="custom-block-title">提示</p><p>建议将工作目录设置在 SSD 硬盘上，可以显著提升计算和读写速度。</p></div><div class="warning custom-block"><p class="custom-block-title">注意</p><p>DEFORM 是商业软件，请确保使用正版授权。</p></div>`,42)])])}const u=t(l,[["render",d]]);export{b as __pageData,u as default};
